import{_ as e,c as t,o as a,f as i}from"./chunks/framework.BOAZPCR7.js";const _=JSON.parse('{"title":"Mutations to the HCoV-229E spike have counterbalancing effects on serum antibody neutralization and receptor binding","description":"","frontmatter":{"layout":"paper","title":"Mutations to the HCoV-229E spike have counterbalancing effects on serum antibody neutralization and receptor binding","date":"2026-02-22","authors":["Sheri Harari","Rachel T Eguia","Bernadeta Dadonaite","Caelan E Radford","Cameron Stewart","David Veesler","Jesse D Bloom"],"journal":"bioRxiv","doi":"10.64898/2026.02.22.707297","link":"https://doi.org/10.64898/2026.02.22.707297","image":"/assets/papers/2026_harari.png","keywords":["Coronavirus","Deep mutational scanning","Pseudovirus"],"selected":false,"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2026_harari.html"}]]},"headers":[],"relativePath":"papers/2026_harari.md","filePath":"papers/2026_harari.md"}'),r={name:"papers/2026_harari.md"},n=i('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Human coronavirus 229E (HCoV-229E) is an endemic pathogen that causes repeated &quot;common-cold&quot; infections throughout life. Like other coronaviruses, it accumulates spike mutations that erode antibody immunity and enable reinfection. Here, we use pseudovirus deep mutational scanning to measure how mutations to the HCoV-229E spike affect its cell entry function, binding to its human APN receptor, and neutralization by human sera with a range of sensitivities to erosion by viral evolution. We find that both receptor binding and serum neutralization are affected by mutations across spike, including many that modulate these properties by affecting the balance of up versus down conformations of the spike receptor-binding domain (RBD). In particular, some mutations increase both receptor binding and serum neutralization by shifting the RBD to a more up conformation, suggesting that the HCoV-229E spike has evolved to shield key RBD neutralizing epitopes at the cost of less efficient receptor binding.</p><h2 id="interactive-visualizations" tabindex="-1">Interactive visualizations <a class="header-anchor" href="#interactive-visualizations" aria-label="Permalink to &quot;Interactive visualizations&quot;">​</a></h2><p>The results described in this paper can be interactively visualized at <a href="https://dms-vep.org/229E_spike_1984_DMS/" target="_blank" rel="noreferrer">https://dms-vep.org/229E_spike_1984_DMS/</a>; all computer code and data is at <a href="https://github.com/dms-vep/229E_spike_1984_DMS" target="_blank" rel="noreferrer">https://github.com/dms-vep/229E_spike_1984_DMS</a>.</p>',4),o=[n];function s(c,d,l,p,u,h){return a(),t("div",null,o)}const f=e(r,[["render",s]]);export{_ as __pageData,f as default};
